import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Link } from 'react-router-dom';
import Layout from '../../components/shared/Layout';
import { fetchMyAccounts } from '../../store/slices/accountSlice';

const Card = ({ title, value, sub, color, to }) => (
  <Link to={to || '#'} style={{ textDecoration: 'none' }}>
    <div style={{ background: '#fff', borderRadius: 12, padding: '20px 24px', boxShadow: '0 2px 8px rgba(0,0,0,0.06)', borderLeft: `4px solid ${color}`, cursor: to ? 'pointer' : 'default', height: '100%' }}>
      <p style={{ margin: 0, color: '#64748b', fontSize: 13 }}>{title}</p>
      <h3 style={{ margin: '4px 0 2px', color: '#1e293b', fontSize: 22 }}>{value}</h3>
      {sub && <p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>{sub}</p>}
    </div>
  </Link>
);

const statusColor = { ACTIVE: '#22c55e', AT_RISK: '#f59e0b', DEACTIVATED: '#ef4444', REQUESTED: '#3b82f6', REJECTED: '#94a3b8' };

export default function CustomerDashboard() {
  const dispatch = useDispatch();
  const { user } = useSelector(s => s.auth);
  const { accounts, loading } = useSelector(s => s.accounts);

  useEffect(() => { dispatch(fetchMyAccounts()); }, [dispatch]);

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 style={{ margin: '0 0 4px', color: '#1e293b' }}>Welcome, {user?.name} </h2>
        <p style={{ color: '#64748b', margin: '0 0 28px' }}>Here's your financial overview</p>
      </div>

      {loading && <p>Loading accounts...</p>}

      {accounts.map(acc => (
        <div key={acc.accountNumber} style={{ background: '#fff', borderRadius: 12, padding: 24, marginBottom: 20, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
          <div className="d-flex justify-content-between align-items-start flex-wrap gap-2">
            <div>
              <p style={{ margin: 0, color: '#64748b', fontSize: 13 }}>{acc.accountType} ACCOUNT</p>
              <h3 style={{ margin: '4px 0', color: '#1e293b', fontFamily: 'monospace', fontSize: 18 }}>{acc.accountNumber}</h3>
            </div>
            <span style={{ padding: '4px 12px', borderRadius: 99, background: statusColor[acc.status] + '20', color: statusColor[acc.status], fontWeight: 700, fontSize: 13 }}>{acc.status}</span>
          </div>
          <div className="d-flex flex-wrap gap-4 mt-3">
            <div>
              <p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>Balance</p>
              <h2 style={{ margin: '4px 0', color: '#1e293b' }}>₹{acc.balance?.toLocaleString('en-IN')}</h2>
            </div>
            {acc.accountType === 'CURRENT' && (
              <div>
                <p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>Overdraft Limit</p>
                <h2 style={{ margin: '4px 0', color: '#64748b' }}>₹{acc.overdraftLimit?.toLocaleString('en-IN')}</h2>
              </div>
            )}
          </div>
          {acc.status === 'AT_RISK' && (
            <div style={{ marginTop: 16, padding: '12px 16px', background: '#fef3c7', borderRadius: 8, border: '1px solid #f59e0b', color: '#92400e', fontSize: 13 }}>
              ⚠️ <strong>Account AT RISK</strong> — Your balance has reached zero. Please deposit funds within 24 hours to prevent auto-deactivation.
            </div>
          )}
          {acc.status === 'DEACTIVATED' && acc.deactivationType === 'AUTO' && (
            <div style={{ marginTop: 16, padding: '12px 16px', background: '#fee2e2', borderRadius: 8, border: '1px solid #ef4444', color: '#991b1b', fontSize: 13 }}>
               Account auto-deactivated due to zero balance. Deposit funds to reactivate.
            </div>
          )}
        </div>
      ))}

      <div className="row g-3 mt-1">
        <div className="col-12 col-sm-6 col-lg-4 col-xl-3"><Card title="Passbook" value=" View" color="#3b82f6" to="/transactions" /></div>
        <div className="col-12 col-sm-6 col-lg-4 col-xl-3"><Card title="Transfer Money" value=" Send" color="#8b5cf6" to="/transfer" /></div>
        <div className="col-12 col-sm-6 col-lg-4 col-xl-3"><Card title="Investments" value=" Manage" color="#22c55e" to="/investments" /></div>
        <div className="col-12 col-sm-6 col-lg-4 col-xl-3"><Card title="Loans" value=" Apply" color="#f59e0b" to="/loans" /></div>
        <div className="col-12 col-sm-6 col-lg-4 col-xl-3"><Card title="Support" value=" Chat" color="#ec4899" to="/chat" /></div>
      </div>
    </Layout>
  );
}
